import React from 'react';

import educationIcon from '../icons/mortarboard.png';
import groceryIcon from '../icons/groceries.png';
import closesIcon from '../icons/tshirt.png';
import carIcon from '../icons/car.png';
import taxiIcon from '../icons/taxi.png';
import sportIcon from '../icons/barbell.png';
import gameIcon from '../icons/game-pad.png';
import cafeIcon from '../icons/restaurant.png';
import healthIcon from '../icons/heartbeat.png';
import travelIcon from '../icons/plane.png';

import './expense-item.css';

const ExpenseCategory = (props) => {
    const getPercent = (num) => {
        if (num === props.max) {
            return '100%';
        };

        return Math.round((num / props.max) * 100) + '%';
    };

    const types = [
        {img: educationIcon, color: 'education', name: 'Образование', amount: props.categories[0], percents: getPercent(props.categories[0])},
        {img: groceryIcon, color: 'grocery', name: 'Еда', amount: props.categories[1], percents: getPercent(props.categories[1])},
        {img: closesIcon, color: 'closes', name: 'Одежда', amount: props.categories[2], percents: getPercent(props.categories[2])},
        {img: carIcon, color: 'car', name: 'Машина', amount: props.categories[3], percents: getPercent(props.categories[3])},
        {img: taxiIcon, color: 'taxi', name: 'Такси', amount: props.categories[4], percents: getPercent(props.categories[4])},
        {img: sportIcon, color: 'sport', name: 'Спорт и фитнес', amount: props.categories[5], percents: getPercent(props.categories[5])},
        {img: gameIcon, color: 'games', name: 'Игры и развлечения', amount: props.categories[6], percents: getPercent(props.categories[6])},
        {img: cafeIcon, color: 'cafe', name: 'Кафе и рестораны', amount: props.categories[7], percents: getPercent(props.categories[7])},
        {img: healthIcon, color: 'health', name: 'Здоровье', amount: props.categories[8], percents: getPercent(props.categories[8])},
        {img: travelIcon, color: 'travel', name: 'Путешествия', amount: props.categories[9], percents: getPercent(props.categories[9])},
    ];

    const content = types.map((type) => {
        return <li key={type.name} className='item'>
            <img src={type.img} alt=''/>
            <div className='item-z'>{type.name}</div>
            <div className='item-z'>{type.amount}</div>
            <div className={`item-fill ${type.color}`} style={{width: type.percents}}></div>
        </li>;
    });

    return (
        <div>
            {content}
        </div>
    );
};

export default ExpenseCategory;