import React from 'react';

import classes from './expense-filter.module.css';

const ExpenseFilter = (props) => {
    const onSelectMonth = (event) => {
        props.onChangeMonth(event.target.value);
        props.onChangeIsFiltered(true);
    };

    const onSelectYear = (event) => {
        props.onChangeYear(event.target.value);
        props.onChangeIsFiltered(true);
    };

    return (
        <div className={classes.filter}>
            <div className={classes['filter-item']}>
                <label>Выберите месяц</label>
                <select value={props.selectedMonth} onChange={onSelectMonth}>
                    <option value='0'>Январь</option>
                    <option value='1'>Февраль</option>
                    <option value='2'>Март</option>
                    <option value='3'>Апрель</option>
                    <option value='4'>Май</option>
                    <option value='5'>Июнь</option>
                    <option value='6'>Июль</option>
                    <option value='7'>Август</option>
                    <option value='8'>Сентябрь</option>
                    <option value='9'>Октябрь</option>
                    <option value='10'>Ноябрь</option>
                    <option value='11'>Декабрь</option>
                    <option value=''>---</option>
                </select>
            </div>
            <div className={classes['filter-item']}>
                <label>Выберите год</label>
                <select value={props.selectedYear} onChange={onSelectYear}>
                    <option value='2019'>2019</option>
                    <option value='2020'>2020</option>
                    <option value='2021'>2021</option>
                    <option value=''>---</option>
                </select>
            </div>
            <button onClick={props.onResetFilters}>Сбросить фильтры</button>
        </div>
    );
}

export default ExpenseFilter;