import React, {useState} from 'react';

import classes from './add-expense.module.css';

const AddExpense = (props) => {
    const [enteredName, setEnteredName] = useState('');
    const [enteredAmount, setEnteredAmount] = useState('');
    const [enteredType, setEnteredType] = useState('0');
    const [enteredDate, setEnteredDate] = useState('');

    const nameChangeHandler = (event) => {
        setEnteredName(event.target.value);
    };

    const amountChangeHandler = (event) => {
        setEnteredAmount(event.target.value);
    };

    const typeChangeHandler = (event) => {
        setEnteredType(event.target.value);
    };

    const dateChangeHandler = (event) => {
        setEnteredDate(event.target.value);
    };

    const addExpenseHandler = (event) => {
        event.preventDefault();

        let selectedDate;

        if (enteredDate.trim().length === 0) {
            selectedDate = new Date();
        } else {
            selectedDate = new Date(enteredDate);
        };

        const newExpense = {
            title: enteredName,
            amount: +enteredAmount,
            category: enteredType,
            date: selectedDate,
        };

        if (enteredName.trim().length === 0) {
            newExpense.title = 'Другое';
        };

        props.onAddExpense(newExpense);

        setEnteredName('');
        setEnteredAmount('');
        setEnteredType('0');
        setEnteredDate('');
    };

    return (
        <form className={classes['add-expense']}>
            <div className={classes['add-expense-text']}>
                <label>Название</label>
                <input type='text' value={enteredName} onChange={nameChangeHandler}></input>
            </div>
            <div className={classes['add-expense-number']}>
                <label>Сумма</label>
                <input type='number' value={enteredAmount} onChange={amountChangeHandler}></input>
            </div>
            <div>
                <label>Выберите тип</label>
                <select onChange={typeChangeHandler} value={enteredType}>
                    <option value='0'>Образование</option>
                    <option value='1'>Еда</option>
                    <option value='2'>Одежда</option>
                    <option value='3'>Машина</option>
                    <option value='4'>Такси</option>
                    <option value='5'>Спорт и фитнес</option>
                    <option value='6'>Игры и разлечения</option>
                    <option value='7'>Кафе и рестораны</option>
                    <option value='8'>Здоровье</option>
                    <option value='9'>Путешествия</option>
                </select>
            </div>
            <div>
                <label>Дата</label>
                <input type='date' min='2019-01-01' max='2021-12-31' value={enteredDate} onChange={dateChangeHandler}></input>
            </div>
            <button type='submit' onClick={addExpenseHandler}>Добавить</button>
            <button>Отмена</button>
        </form>
    );
};

export default AddExpense;